def range_summary(nums):
    if not nums:
        return ''
    runs = []
    prev, count = nums[0], 1
    for num in nums[1:]:
        if num == prev + 1:
            count += 1
        else:
            runs.append((prev, count))
            count = 1 if num == prev else 1
    runs.append((nums[-1], count))

    return ', '.join('-'.join(map(str, run)) for run in runs)
